import React from "react";

export default function TransactionReceiptScreen({ transaction, goBack }) {
  if (!transaction) return null;

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <button onClick={goBack} className="mb-6 text-teal-600 font-medium">
        ← Back
      </button>

      <h1 className="text-2xl font-bold mb-6">Transaction Receipt</h1>

      <div className="bg-white p-6 rounded-xl space-y-3 border border-gray-100 shadow-sm">
        <p><strong>Type:</strong> {transaction.type}</p>
        <p><strong>Title:</strong> {transaction.title}</p>
        <p><strong>Amount:</strong> ${transaction.amount}</p>
        <p><strong>Date:</strong> {transaction.date}</p>
        <p><strong>Reference:</strong> #{transaction.id}</p>
      </div>
    </div>
  );
}
